class Solution(object):
    def numSub(self, s):
        """
        :type s: str
        :rtype: int
        """
        count = 0
        s = s.strip('0').split('0')
        for i in s:
            summ = sum(range(1, len(i) + 1))
            count += summ
        return count % (10 ** 9 + 7)



